// Topic: akilli-sinif/sinif-1/sensors/temperature
var parts = msg.topic.split('/');
var classroomId = parts[1];  // sinif-1
var sensorType = parts[3];   // temperature, humidity, camera, etc.

// Sensör tipine göre field adını belirle
var fieldName = "value";
var fieldValue = msg.payload.value;

// Boolean sensörler için özel işlem
if (sensorType === "pir") {
    fieldName = "detected";
    fieldValue = msg.payload.detected ? 1 : 0;
} else if (sensorType === "window") {
    fieldName = "open";
    fieldValue = msg.payload.open ? 1 : 0;
} else if (sensorType === "camera") {
    fieldName = "person_count";
    fieldValue = msg.payload.person_count || 0;
}

// InfluxDB v2 için mesajı hazırla
msg.measurement = sensorType;
var fields = {};
fields[fieldName] = fieldValue;

// Akim sensoru icin ham ADC degerini de kaydet (kalibrasyon icin)
if (sensorType === "current" && msg.payload.raw !== undefined) {
    fields.raw = msg.payload.raw;
}

var tags = {
    classroom: classroomId,
    sensor: sensorType
};
msg.payload = [fields, tags];

return msg;

var parts = msg.topic.split('/');
var classroomId = parts[1];

msg.measurement = "device_status";
msg.payload = [
    {
        online: msg.payload.status === "online" ? 1 : 0,
        rssi: msg.payload.rssi || 0,
        uptime: msg.payload.uptime || 0
    },
    {
        classroom: classroomId,
        device: msg.payload.device || "unknown"
    }
];

return msg;

// Topic'e göre sensör verilerini global context'e kaydet
var parts = msg.topic.split('/');
var classroomId = parts[1];
var sensorType = parts[3];

// Global context key
var key = classroomId + '_' + sensorType;

// Sensör değerini kaydet
if (sensorType === 'camera') {
    global.set(classroomId + '_person_count', msg.payload.person_count || 0);
    return [msg, null, null];  // Output 1: Kişi sayısı değişti
} else if (sensorType === 'temperature') {
    global.set(classroomId + '_temperature', msg.payload.value);
    return [null, msg, null];  // Output 2: Sıcaklık değişti
} else if (sensorType === 'light') {
    global.set(classroomId + '_light', msg.payload.value);
    return [null, null, msg];  // Output 3: Işık değişti
} else if (sensorType === 'pir') {
    // PIR durumu sadece global context'e kaydedilir.
    // check-light bir sonraki ışık okumasında bu değeri kullanır.
    global.set(classroomId + '_pir_detected', msg.payload.detected || false);
}

return null;

// Kişi sayısı değiştiğinde kontrol et
var parts = msg.topic.split('/');
var classroomId = parts[1];
var personCount = msg.payload.person_count || 0;

var autoMode = global.get(classroomId + '_auto_mode');
if (autoMode === false) {
    return null;
}

if (personCount === 0) {
    var emptyTimer = global.get(classroomId + '_empty_timer');

    if (!emptyTimer) {
        global.set(classroomId + '_empty_since', Date.now());
        global.set(classroomId + '_empty_timer', true);
        node.status({fill:'yellow', shape:'ring', text:'Sınıf boş, bekleniyor...'});
    }

    var emptySince = global.get(classroomId + '_empty_since');
    var elapsed = Date.now() - emptySince;

    if (elapsed >= 300000) {  // 5 dakika
        // LED + Cooling + Heating kapat
        node.status({fill:'red', shape:'dot', text:'5 dk boş - Kapatılıyor'});

        msg.classroomId = classroomId;
        msg.action = 'turn_off_all';
        return msg;
    }
} else {
    global.set(classroomId + '_empty_timer', false);
    global.set(classroomId + '_empty_since', null);
    node.status({fill:'green', shape:'dot', text:personCount + ' kişi var'});
}

return null;

var classroomId = msg.classroomId || 'sinif-1';

var ledMsg = {
    topic: 'akilli-sinif/' + classroomId + '/control/led',
    payload: { brightness: 0, reason: 'auto_empty' }
};

var coolingMsg = {
    topic: 'akilli-sinif/' + classroomId + '/control/cooling',
    payload: { state: 'off', reason: 'auto_empty' }
};

var heatingMsg = {
    topic: 'akilli-sinif/' + classroomId + '/control/heating',
    payload: { state: 'off', reason: 'auto_empty' }
};

node.status({fill:'red', shape:'dot', text:'LED+Cooling+Heating kapatıldı'});

return [ledMsg, coolingMsg, heatingMsg];

// Sıcaklık değiştiğinde cooling ve heating histeresisini değerlendir
var parts = msg.topic.split('/');
var classroomId = parts[1];
var temperature = msg.payload.value;

var personCount = global.get(classroomId + '_person_count') || 0;
var autoMode = global.get(classroomId + '_auto_mode');
if (autoMode === false || personCount === 0) {
    return null;  // Manuel mod veya sınıf boş — otomasyon devre dışı
}

// PLC firmware ile aynı eşikler
var COOL_ON = 26;   // > 26°C  -> cooling ON
var COOL_OFF = 24;  // < 24°C  -> cooling OFF
var HEAT_ON = 20;   // < 20°C  -> heating ON
var HEAT_OFF = 22;  // > 22°C  -> heating OFF

var coolState = global.get(classroomId + '_cooling_auto_state') || false;
var heatState = global.get(classroomId + '_heating_auto_state') || false;

var coolingMsg = null;
var heatingMsg = null;

if (temperature > COOL_ON && !coolState) {
    global.set(classroomId + '_cooling_auto_state', true);
    coolingMsg = {
        topic: 'akilli-sinif/' + classroomId + '/control/cooling',
        payload: { state: 'on', reason: 'auto_temp' }
    };
} else if (temperature < COOL_OFF && coolState) {
    global.set(classroomId + '_cooling_auto_state', false);
    coolingMsg = {
        topic: 'akilli-sinif/' + classroomId + '/control/cooling',
        payload: { state: 'off', reason: 'auto_temp' }
    };
}

if (temperature < HEAT_ON && !heatState) {
    global.set(classroomId + '_heating_auto_state', true);
    heatingMsg = {
        topic: 'akilli-sinif/' + classroomId + '/control/heating',
        payload: { state: 'on', reason: 'auto_temp' }
    };
} else if (temperature > HEAT_OFF && heatState) {
    global.set(classroomId + '_heating_auto_state', false);
    heatingMsg = {
        topic: 'akilli-sinif/' + classroomId + '/control/heating',
        payload: { state: 'off', reason: 'auto_temp' }
    };
}

var label = temperature + '°C';
if (coolingMsg) label += ' cool=' + coolingMsg.payload.state;
if (heatingMsg) label += ' heat=' + heatingMsg.payload.state;
node.status({fill: (coolingMsg||heatingMsg)?'orange':'grey', shape: 'dot', text: label});

return [coolingMsg, heatingMsg];

// Işık seviyesi değiştiğinde kontrol et
var parts = msg.topic.split('/');
var classroomId = parts[1];
var lightLevel = msg.payload.value;

// Varlık tespiti: PIR (donanım, hareket) OR YOLO (görsel, sabit kişi)
// İkisi birbirini tamamlar — PIR ölü açıda YOLO yedek, YOLO offline'da PIR yedek.
var personCount = global.get(classroomId + '_person_count') || 0;
var motionDetected = global.get(classroomId + '_pir_detected') || false;
var presence = motionDetected || personCount > 0;

// Otomasyon durumunu kontrol et
var autoMode = global.get(classroomId + '_auto_mode');
if (autoMode === false || !presence) {
    return null;  // Manuel mod veya sınıf gerçekten boş
}

// Işık eşikleri
var LED_ON_THRESHOLD = 300;   // 300 lux altında LED aç
var LED_OFF_THRESHOLD = 500;  // 500 lux üstünde LED kapat

var currentLedState = global.get(classroomId + '_led_auto_state') || false;

if (lightLevel < LED_ON_THRESHOLD && !currentLedState) {
    // Karanlık - LED aç
    global.set(classroomId + '_led_auto_state', true);
    node.status({fill:'yellow', shape:'dot', text:lightLevel + ' lux - LED açılıyor'});

    // LED parlaklığını ışık seviyesine göre ayarla
    var ledBrightness = 100;
    if (lightLevel > 200) ledBrightness = 75;
    if (lightLevel > 250) ledBrightness = 50;

    msg.topic = 'akilli-sinif/' + classroomId + '/control/led';
    msg.payload = { brightness: ledBrightness, reason: 'auto_light' };
    return msg;

} else if (lightLevel > LED_OFF_THRESHOLD && currentLedState) {
    // Aydınlık - LED kapat
    global.set(classroomId + '_led_auto_state', false);
    node.status({fill:'green', shape:'dot', text:lightLevel + ' lux - LED kapatılıyor'});

    msg.topic = 'akilli-sinif/' + classroomId + '/control/led';
    msg.payload = { brightness: 0, reason: 'auto_light' };
    return msg;
}

node.status({fill:'grey', shape:'ring', text:lightLevel + ' lux'});
return null;

// Her 30 saniyede bir sınıf boş mu kontrol et
var classroomId = 'sinif-1';
var personCount = global.get(classroomId + '_person_count') || 0;

// Kamera verisi simüle et
msg.topic = 'akilli-sinif/' + classroomId + '/sensors/camera';
msg.payload = { person_count: personCount };

return msg;

var autoMode = msg.payload;
global.set('sinif-1_auto_mode', autoMode);

if (autoMode) {
    node.status({fill:'green', shape:'dot', text:'Otomasyon AÇIK'});
} else {
    node.status({fill:'red', shape:'dot', text:'Otomasyon KAPALI'});
}

return msg;

// Topic: akilli-sinif/sinif-1/status/{led|cooling|heating}
var parts = msg.topic.split('/');
var classroomId = parts[1];
var actuatorType = parts[3];

if (actuatorType === 'led') {
    msg.measurement = 'led_status';
    msg.payload = [
        { brightness: msg.payload.brightness || 0 },
        { classroom: classroomId, reason: msg.payload.reason || 'manual' }
    ];
} else if (actuatorType === 'cooling') {
    msg.measurement = 'cooling_status';
    msg.payload = [
        { state: (msg.payload.state === 'on') ? 1 : 0 },
        { classroom: classroomId, reason: msg.payload.reason || 'manual' }
    ];
} else if (actuatorType === 'heating') {
    msg.measurement = 'heating_status';
    msg.payload = [
        { state: (msg.payload.state === 'on') ? 1 : 0 },
        { classroom: classroomId, reason: msg.payload.reason || 'manual' }
    ];
} else {
    return null;
}

return msg;

// Otomasyon olaylarını kaydet
var classroomId = msg.classroomId || 'sinif-1';
var reason = msg.payload.reason || 'unknown';

var actuator = 'unknown';
var value = 0;
if (msg.topic.includes('/control/led')) {
    actuator = 'led';
    value = msg.payload.brightness || 0;
} else if (msg.topic.includes('/control/cooling')) {
    actuator = 'cooling';
    value = (msg.payload.state === 'on') ? 1 : 0;
} else if (msg.topic.includes('/control/heating')) {
    actuator = 'heating';
    value = (msg.payload.state === 'on') ? 1 : 0;
}

msg.measurement = 'automation_event';
msg.payload = [
    { value: value, reason: reason },
    { classroom: classroomId, actuator: actuator }
];

return msg;

// GitHub API yanıtını işle
var release = msg.payload;

if (!release || !release.tag_name) {
    node.status({fill:'red', shape:'dot', text:'API hatası veya repo bulunamadı'});
    node.warn('GitHub API hatası: ' + JSON.stringify(release));
    return null;
}

var tagName = release.tag_name;
var assets  = release.assets || [];

var plcUrl = '', camUrl = '', simUrl = '';
var plcVer = '', camVer = '', simVer = '';

assets.forEach(function(asset) {
    // SADECE .bin asset'leri eslestir. .md5 sidecar'i da 'firmware-plc'
    // icerir; atlamazsak plcUrl'i .md5 URL'i ile ezer → firmware .md5'i
    // binary sanip .bin.md5.md5 arar → md5_unavailable hatasi.
    if (!asset.name.endsWith('.bin')) return;
    var m   = asset.name.match(/v(\d+\.\d+\.\d+)/);
    var ver = m ? m[1] : tagName.replace('v', '');
    if (asset.name.includes('firmware-plc')) { plcUrl = asset.browser_download_url; plcVer = ver; }
    if (asset.name.includes('firmware-cam')) { camUrl = asset.browser_download_url; camVer = ver; }
    if (asset.name.includes('firmware-sim')) { simUrl = asset.browser_download_url; simVer = ver; }
});

global.set('ota_latest_tag',  tagName);
global.set('ota_plc_url',     plcUrl);
global.set('ota_cam_url',     camUrl);
global.set('ota_sim_url',     simUrl);
global.set('ota_plc_version', plcVer);
global.set('ota_cam_version', camVer);
global.set('ota_sim_version', simVer);
global.set('ota_release_name', release.name || tagName);
global.set('ota_release_date', release.published_at);

node.status({fill:'green', shape:'dot', text:'Son: ' + tagName + ' (' + (new Date(release.published_at)).toLocaleDateString('tr-TR') + ')'});

msg.payload = {
    tag:     tagName,
    plc_url: plcUrl, plc_ver: plcVer,
    cam_url: camUrl, cam_ver: camVer,
    sim_url: simUrl, sim_ver: simVer,
    date:    release.published_at
};

return msg;

var deviceType = msg.payload;  // 'plc' veya 'cam'

var version = deviceType === 'plc' ? global.get('ota_plc_version') : global.get('ota_cam_version');
var url     = deviceType === 'plc' ? global.get('ota_plc_url')     : global.get('ota_cam_url');

if (!version || !url) {
    node.error('Versiyon bilgisi yok! Önce GitHub kontrolü yap.');
    node.status({fill:'red', shape:'dot', text:'Versiyon bilinmiyor'});
    return null;
}

// ROBUSTLUK: global stale .md5 sidecar URL tutuyorsa .bin'e duzelt
// (parse fix oncesi context'te kalmis olabilir) -> md5_unavailable onler.
if (url && url.endsWith('.md5')) url = url.slice(0, -4);

node.status({fill:'yellow', shape:'dot', text:'Gönderiliyor: v' + version});

// md5 sidecar'i Node-RED ceker (redirect takip eder); cihaz fetch yapmaz
msg.fwTopic   = 'akilli-sinif/sinif-1/control/ota';
msg.fwVersion = version;
msg.fwBinUrl  = url;
msg.fwDevice  = deviceType;
msg.url       = url + '.md5';
return msg;

var version = global.get('ota_sim_version');
var url     = global.get('ota_sim_url');

if (!version || !url) {
    node.error('Versiyon bilgisi yok! Önce GitHub kontrolü yap.');
    node.status({fill:'red', shape:'dot', text:'Versiyon bilinmiyor'});
    return null;
}

// ROBUSTLUK: global stale .md5 sidecar URL tutuyorsa .bin'e duzelt
// (parse fix oncesi context'te kalmis olabilir) -> md5_unavailable onler.
if (url && url.endsWith('.md5')) url = url.slice(0, -4);

node.status({fill:'yellow', shape:'dot', text:'Gönderiliyor: v' + version});

// md5 sidecar'i Node-RED ceker (redirect takip eder); cihaz fetch yapmaz
msg.fwTopic   = 'akilli-sinif/sinif-2/control/ota';
msg.fwVersion = version;
msg.fwBinUrl  = url;
msg.fwDevice  = 'sim';
msg.url       = url + '.md5';
return msg;

var deviceType = msg.payload;  // 'plc' veya 'cam'

var version = deviceType === 'plc' ? global.get('ota_plc_version') : global.get('ota_cam_version');
var url     = deviceType === 'plc' ? global.get('ota_plc_url')     : global.get('ota_cam_url');

if (!version || !url) {
    node.error('Versiyon bilgisi yok! Önce GitHub kontrolü yap.');
    node.status({fill:'red', shape:'dot', text:'Versiyon bilinmiyor'});
    return null;
}

// ROBUSTLUK: global stale .md5 sidecar URL tutuyorsa .bin'e duzelt
// (parse fix oncesi context'te kalmis olabilir) -> md5_unavailable onler.
if (url && url.endsWith('.md5')) url = url.slice(0, -4);

node.status({fill:'yellow', shape:'dot', text:'Tüm ' + deviceType.toUpperCase() + ' → v' + version});

// md5 sidecar'i Node-RED ceker (redirect takip eder); cihaz fetch yapmaz
msg.fwTopic   = 'akilli-sinif/all/control/ota';
msg.fwVersion = version;
msg.fwBinUrl  = url;
msg.fwDevice  = deviceType;
msg.url       = url + '.md5';
return msg;

var parts      = msg.topic.split('/');
var classroomId = parts[1];
var status      = msg.payload.status;
var progress    = msg.payload.progress || -1;
var version     = msg.payload.target_version || '';
var error       = msg.payload.error || '';
var curVersion  = msg.payload.current_version || '';

var logKey = classroomId + '_ota_status';
global.set(logKey, {
    status:  status,
    version: version,
    updated: new Date().toLocaleTimeString('tr-TR')
});

var statusText = '';
var color = 'grey';

switch(status) {
    case 'updating':
        color = 'yellow';
        statusText = classroomId + ': İndiriliyor ' + progress + '%';
        break;
    case 'success':
        color = 'green';
        statusText = classroomId + ': ✅ ' + version + ' başarılı!';
        // Mevcut versiyon bilgisini güncelle
        global.set(classroomId + '_firmware_version', version);
        break;
    case 'failed':
        color = 'red';
        statusText = classroomId + ': ❌ Hata: ' + error;
        break;
    case 'up_to_date':
        color = 'blue';
        statusText = classroomId + ': Zaten güncel (' + curVersion + ')';
        break;
    default:
        statusText = classroomId + ': ' + status;
}

node.status({fill: color, shape: 'dot', text: statusText});

// Log mesajı
msg.logText = '[' + new Date().toLocaleTimeString('tr-TR') + '] ' + statusText;

return msg;

var parts       = msg.topic.split('/');
var classroomId  = parts[1];
var fwVersion    = msg.payload.firmware_version || 'bilinmiyor';
var device       = msg.payload.device || 'unknown';
var mockMode     = msg.payload.mock_mode || false;

global.set(classroomId + '_firmware_version', fwVersion);
global.set(classroomId + '_device_id',        device);

var latestVersion;
if      (device.includes('plc')) latestVersion = global.get('ota_plc_version') || '?';
else if (device.includes('cam')) latestVersion = global.get('ota_cam_version') || '?';
else if (device.includes('sim')) latestVersion = global.get('ota_sim_version') || '?';
else                             latestVersion = '?';

var upToDate = (fwVersion === latestVersion);

var statusText = classroomId + ' (' + device + '): v' + fwVersion;
if (latestVersion !== '?') {
    statusText += upToDate ? ' ✅ güncel' : ' ⚠️ güncelleme var: v' + latestVersion;
}

node.status({fill: upToDate ? 'green' : 'yellow', shape: 'dot', text: statusText});

msg.logText = statusText;
return msg;

var classroomId = msg.payload;  // 'sinif-1', 'sinif-2', vs.

msg.topic   = 'akilli-sinif/' + classroomId + '/control/reset';
msg.payload = JSON.stringify({ action: 'reset_config' });

node.status({fill:'yellow', shape:'dot', text: classroomId + ' sıfırlanıyor...'});

return msg;

// Node-RED'in indirdigi md5 metnini payload'a gom -> cihaz sidecar fetch yapmaz
var md5 = (msg.payload || '').toString().trim().split(/\s+/)[0];
if (!/^[0-9a-fA-F]{32}$/.test(md5)) {
    node.error('md5 sidecar gecersiz/alinamadi: ' + JSON.stringify(msg.payload));
    node.status({fill:'red', shape:'dot', text:'md5 alinamadi'});
    return null;
}
msg.topic   = msg.fwTopic;
msg.payload = JSON.stringify({
    action:  'update',
    version: msg.fwVersion,
    url:     msg.fwBinUrl,
    md5:     md5.toLowerCase(),
    device:  msg.fwDevice
});
node.status({fill:'green', shape:'dot', text:'md5 ok -> gonderiliyor'});
return msg;
